var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"다이브 작전이라...... 예전 생각 나네.","JPN":"ダイブ作戦か……少し前のことを思い出すな。","ENG":"A Dive operation, huh... It reminds me of back in the day...","TWN":"躍入作戰……想起以前的事了呢。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그 때는 정말 난리도 아니었지.","JPN":"あの時は本当に散々だった。","ENG":"Things got really hectic back then.","TWN":"當時真是一團糟。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"알트 소대는 멋대로 사라지지 않나, 그림자라는 게 튀어나오지 않나......","JPN":"アルト小隊は勝手に消えるし、シャドウとかいうのがいきなり出てきて……","ENG":"The ALT Squad went AWOL, and those Shadow things popped out of nowhere...","TWN":"阿爾特小隊自作主張消失了，還出現了暗影……"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그 때에 비하면 이번 다이브는 정말 평화......","JPN":"あの時に比べれば今回のダイブは本当に平和……","ENG":"Compared to that, this Dive is pretty peaceful—","TWN":"比起那時，這次的躍入真是平靜……"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"자기가 먼저 도망치면 어떡해요, 선배?! 후배를 지켜 줘야죠!","JPN":"先に逃げてどうするんですか、先輩！？　後輩を守るべきでしょう！？","ENG":"You can't run away, Ray! You should protect your underclassmen!","TWN":"你怎麼能自己先跑呢，前輩？！你要保護後輩啊！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"그, 그치만 나도 침식체한테 공격 받으면 아픈걸......","JPN":"だ、だって僕も侵食体に攻撃されたら痛いんだよ……","ENG":"B-but those C.O.s could hurt me too...","TWN":"但，我如果被侵蝕體攻擊也會疼的啊……"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"어휴! 듬직한 구석이 없어, 진짜!","JPN":"もお！　頼もしいところが1ミリもないんだから！","ENG":"Gosh! You're totally unreliable!","TWN":"哎～真是的！一點也靠不住！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"꺄아악! 미나야! 살려 줘!","JPN":"きゃーっ！　ミナちゃーん！　助けて！","ENG":"Eeek! Mina! Help me!","TWN":"啊啊啊! 米娜！救救我！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......롭진 않네.","JPN":"……平和ではないな。","ENG":"I'm taking my words back.","TWN":"……也平靜不了了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잠깐만 기다려! 지금 갈게!","JPN":"待って！　今行くから！","ENG":"Hang on! I'll be right there!","TWN":"等一下！馬上就過去！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"흠......","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"혹시라도 적응 못 하면 어쩌나 했는데, 괜한 걱정이었던 것 같군.","JPN":"もし馴染めなかったらどうしようかと思ったが、余計な心配だったようだな。","ENG":"I guess my concerns about you having trouble acclimating were completely unfounded.","TWN":"本來還擔心你不能適應，現在看起來真是白操心了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"알렌 선생님? 선생님도 훈련에 따라온 거야?","JPN":"アレン先生？　先生も訓練についてきたの？","ENG":"Prof? You tagged along on this Dive?","TWN":"艾倫老師？老師也來參加訓練嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"이번 훈련은 내가 직접 기획한 프로젝트라네. 당연히 동행해야지.","JPN":"今回の訓練は私が企画したプロジェクトだ。同行するのは当たり前だ。","ENG":"This very training program is my brainchild. Of course I'm here.","TWN":"這次的訓練計畫是我負責的，我當然要陪同了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그리고...... 신경이 쓰이는 구석도 있어서.","JPN":"そして……気になることもあってな。","ENG":"Besides... I couldn't help but notice something...","TWN":"還有……有些需要我操心的事。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"신경이 쓰이다니, 뭐가?","JPN":"気になるって？　何が？","ENG":"Notice what?","TWN":"要操心的事？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"서류를 봤는데 레이가 이번 훈련에 자네 팀으로 참가를 신청했더군.","JPN":"書類を確認したが、レイは今回の訓練で君と同じチームとして参加したようだな。","ENG":"I read in the files that Ray volunteered to participate in this Dive on your team.","TWN":"我看了資料，這次訓練中雷伊跟你是一隊的。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};